def page_jalons(profil, cap):
    from datetime import date
    today = date.today()
    st.subheader("PLANNING PATRIMONIAL - SUIVI EN TEMPS REEL")

    st.markdown('<div style="background:#2A1800;border:2px solid #D4A017;border-radius:8px;padding:16px 24px;margin-bottom:20px;text-align:center;"><span style="color:#FFD060;font-size:24px;font-weight:700;">AJOUTER UN FLUX IMPREVU</span></div>', unsafe_allow_html=True)
    with st.expander("Cliquer ici pour saisir"):
        from datetime import date as dt2
        col_n, col_s = st.columns(2)
        with col_n:
            nom_flux = st.text_input("Description", placeholder="Ex: Remboursement CAF, aide exceptionnelle...")
        with col_s:
            sens_flux = st.selectbox("Type", ["entree", "sortie", "info"])
        col_m, col_d, col_c = st.columns(3)
        with col_m:
            montant_flux = st.number_input("Montant (EUR)", value=0.0, min_value=0.0, key="flux_mt")
        with col_d:
            date_flux = st.date_input("Date", value=dt2.today(), key="flux_dt")
        with col_c:
            cat_flux = st.selectbox("Categorie", ["imprevu", "caf", "sante", "famille", "administratif", "autre"])
        note_flux = st.text_input("Note (optionnel)", key="flux_note")
        deja_fait = st.checkbox("Deja encaisse/paye", value=True)
        if st.button("Ajouter ce flux"):
            if nom_flux:
                db3 = db_wrapper.connect()
                age_val = 50.5
                fait_val = 1 if deja_fait else 0
                mr_val = montant_flux if deja_fait else 0
                dr_val = str(date_flux) if deja_fait else ''
                db3.execute("""INSERT INTO chronologie
                    (date_cible, age_cible, action, montant, sens, categorie, auto, fait, note, montant_reel, date_reelle)
                    VALUES (%s,%s,%s,%s,%s,%s,0,%s,%s,%s,%s)""",
                    (str(date_flux), age_val, nom_flux, montant_flux, sens_flux, cat_flux, fait_val, note_flux, mr_val, dr_val))
                db3.commit()
                db3.close()
                st.success(f"Flux ajoute : {nom_flux} | {sens_flux} | {montant_flux:,.0f} EUR")
                st.rerun()
            else:
                st.error("Donnez un nom au flux")

    db = db_wrapper.connect()
    # row_factory removed
    c = db.cursor()
    c.execute("SELECT * FROM chronologie ORDER BY date_cible ASC")
    rows = [dict(r) for r in c.fetchall()]
    db.close()

    capital_reel = 0
    for r in rows:
        if r['fait'] == 1 and r['montant'] > 0:
            mr = r['montant_reel'] if r['montant_reel'] else r['montant']
            if r['sens'] == 'entree':
                capital_reel += mr
            elif r['sens'] == 'sortie':
                capital_reel -= mr

    st.metric("CAPITAL REEL CUMULE", f"{capital_reel:,.0f} EUR", delta="Base sur les flux confirmes")
    st.divider()

    a_faire = [r for r in rows if r['fait'] == 0]
    fait = [r for r in rows if r['fait'] == 1]

    # Confirmations 1 mois
    for r in fait:
        if r.get('date_reelle') and r['montant'] > 0:
            try:
                dr = date.fromisoformat(r['date_reelle'])
                jours = (today - dr).days
                if jours >= 30 and r.get('confirme_1mois', 0) == 0:
                    ecart = (r.get('montant_reel', 0) or r['montant']) - r['montant']
                    st.warning(f"CONFIRMATION 1 MOIS : {r['action']} | Prevu: {r['montant']:,.0f} EUR | Reel: {r.get('montant_reel',0):,.0f} EUR | Ecart: {ecart:+,.0f} EUR")
                    c1, c2 = st.columns(2)
                    with c1:
                        if st.button("Confirmer", key=f"c1m_{r['id']}"):
                            db2 = db_wrapper.connect()
                            db2.execute("UPDATE chronologie SET confirme_1mois=1, date_confirme_1mois=%s WHERE id=%s", (str(today), r['id']))
                            db2.commit(); db2.close(); st.rerun()
                    with c2:
                        nv = st.number_input("Corriger montant", value=float(r.get('montant_reel', 0) or r['montant']), key=f"corr1_{r['id']}")
                        if st.button("Corriger", key=f"fix1_{r['id']}"):
                            db2 = db_wrapper.connect()
                            db2.execute("UPDATE chronologie SET montant_reel=%s WHERE id=%s", (nv, r['id']))
                            db2.commit(); db2.close(); st.rerun()
                if jours >= 180 and r.get('confirme_6mois', 0) == 0:
                    st.error(f"VERROUILLAGE 6 MOIS : {r['action']} | Montant: {r.get('montant_reel',0):,.0f} EUR")
                    c1, c2 = st.columns(2)
                    with c1:
                        if st.button("Verrouiller", key=f"c6m_{r['id']}"):
                            db2 = db_wrapper.connect()
                            db2.execute("UPDATE chronologie SET confirme_6mois=1, date_confirme_6mois=%s WHERE id=%s", (str(today), r['id']))
                            db2.commit(); db2.close(); st.rerun()
                    with c2:
                        nv6 = st.number_input("Derniere correction", value=float(r.get('montant_reel', 0) or r['montant']), key=f"corr6_{r['id']}")
                        if st.button("Corriger et verrouiller", key=f"fix6_{r['id']}"):
                            db2 = db_wrapper.connect()
                            db2.execute("UPDATE chronologie SET montant_reel=%s, confirme_6mois=1, date_confirme_6mois=%s WHERE id=%s", (nv6, str(today), r['id']))
                            db2.commit(); db2.close(); st.rerun()
            except:
                pass

    # A venir
    st.subheader("A VENIR")
    for r in a_faire:
        try:
            dt = date.fromisoformat(r['date_cible'])
            jours = (dt - today).days
        except:
            jours = 0
        jours_txt = f"Dans {jours} jours" if jours > 0 else "Maintenant"
        if r['sens'] == 'entree':
            icone = "+"
        elif r['sens'] == 'sortie':
            icone = "-"
        else:
            icone = ""
        flux_txt = f"{icone}{r['montant']:,.0f} EUR" if r['montant'] > 0 else ""

        col1, col2, col3 = st.columns([4, 2, 1])
        with col1:
            st.write(f"**{r['action']}**")
            st.caption(f"{jours_txt} | {r['date_cible']}")
        with col2:
            if flux_txt:
                st.write(f"**{flux_txt}**")
        with col3:
            if r['montant'] > 0:
                if st.button("FAIT", key=f"fait_{r['id']}"):
                    db2 = db_wrapper.connect()
                    db2.execute("UPDATE chronologie SET fait=1, montant_reel=%s, date_reelle=%s WHERE id=%s", (r['montant'], str(today), r['id']))
                    db2.commit(); db2.close(); st.rerun()
            else:
                if st.button("FAIT", key=f"fait_{r['id']}"):
                    db2 = db_wrapper.connect()
                    db2.execute("UPDATE chronologie SET fait=1, date_reelle=%s WHERE id=%s", (str(today), r['id']))
                    db2.commit(); db2.close(); st.rerun()

        if r['montant'] > 0:
            with st.expander(f"Corriger le montant avant de valider"):
                cd, cm = st.columns(2)
                with cd:
                    date_r = st.date_input("Date reelle", value=today, key=f"dr_{r['id']}")
                with cm:
                    montant_r = st.number_input("Montant reel (EUR)", value=float(r['montant']), key=f"mr_{r['id']}")
                ecart = montant_r - r['montant']
                if abs(ecart) > 0:
                    pct = ecart / r['montant'] * 100 if r['montant'] else 0
                    if abs(pct) > 5:
                        st.error(f"Ecart: {ecart:+,.0f} EUR ({pct:+.1f}%) - Verifiez le montant")
                    else:
                        st.warning(f"Ecart: {ecart:+,.0f} EUR ({pct:+.1f}%)")
                if st.button("Valider avec correction", key=f"val_{r['id']}"):
                    db2 = db_wrapper.connect()
                    db2.execute("UPDATE chronologie SET fait=1, montant_reel=%s, date_reelle=%s WHERE id=%s", (montant_r, str(date_r), r['id']))
                    db2.commit(); db2.close(); st.rerun()
        st.divider()

    # Deja fait
    if fait:
        st.markdown('<div style="background:linear-gradient(90deg,#0A2010,#1A4A2A,#0A2010);border:2px solid #4DFF99;border-radius:10px;padding:14px;text-align:center;margin:20px 0;"><span style="font-size:24px;color:#4DFF99;font-weight:900;letter-spacing:4px;">DEJA FAIT</span></div>', unsafe_allow_html=True)
        for r in fait:
            mr = r.get('montant_reel', 0) if r.get('montant_reel', 0) else r['montant']
            icone = "+" if r['sens'] == 'entree' else ("-" if r['sens'] == 'sortie' else "")
            flux_txt = f"{icone}{mr:,.0f} EUR" if mr > 0 else ""
            locks = ""
            if r.get('confirme_1mois'): locks += " [1M]"
            if r.get('confirme_6mois'): locks += " [6M]"
            verrouille = r.get('confirme_6mois', 0) == 1
            col_f, col_a = st.columns([5, 1])
            with col_f:
                st.markdown(f'<div style="background:#0A2010;border-left:4px solid #4DFF99;border-radius:0 6px 6px 0;padding:8px 14px;margin:4px 0;"><span style="color:#4DFF99;font-size:20px;font-weight:900;letter-spacing:3px;text-shadow:0 0 10px #4DFF99;">FAIT</span> <span style="color:#F0E6D8;font-size:14px;">{r.get("date_reelle", "") or r["date_cible"]} | {r["action"]} | {flux_txt}{locks}</span></div>', unsafe_allow_html=True)
            with col_a:
                if not verrouille:
                    if st.button("ANNULER", key=f"undo_{r['id']}"):
                        db_u = db_wrapper.connect()
                        db_u.execute("UPDATE chronologie SET fait=0, montant_reel=0, date_reelle='' WHERE id=%s", (r['id'],))
                        db_u.commit()
                        db_u.close()
                        st.rerun()
                else:
                    st.caption("Verrouille")


def page_jalons_old(profil, cap):
    from datetime import datetime, date
    titre("CHRONOLOGIE COMPLETE - PILOTAGE AUTOMATIQUE")
    age = age_actuel(profil)
    conn = db_wrapper.connect()
    c = conn.cursor()
    try:
        rows = c.execute("SELECT date_cible,age_cible,action,montant,sens,categorie,auto,fait,note FROM chronologie ORDER BY date_cible").fetchall()
    except:
        rows = []
    conn.close()
    if not rows:
        st.warning("Aucune action en chronologie. Lancer patch_chrono.py.")
        return
    # Stats
    total = len(rows)
    faits = sum(1 for r in rows if r[7])
    auto = sum(1 for r in rows if r[6])
    st.markdown(f'<div style="background:#140810;border-radius:10px;padding:14px;margin-bottom:14px;"><div style="color:#E0D0B8;font-size:13px;">{faits}/{total} actions realisees | {auto} automatiques | {total-faits} restantes</div></div>', unsafe_allow_html=True)
    # Filtres
    cats = list(set(r[5] for r in rows))
    cats.sort()
    filtre = st.multiselect("Filtrer par categorie", cats, default=cats)
    for r in rows:
        dt_s, age_j, action, montant, sens, cat, is_auto, fait, note = r
        if cat not in filtre:
            continue
        try:
            dt = datetime.strptime(dt_s, '%Y-%m-%d')
            delta_j = (dt - datetime.today()).days
        except:
            delta_j = 0
        if fait:
            badge_col = "#1A6B4B"; badge_txt = "FAIT"; bg = "#0A1A0A"
        elif delta_j < 0:
            badge_col = "#CC3333"; badge_txt = "EN RETARD"; bg = "#2A0A0A"
        elif delta_j < 90:
            badge_col = "#CC3333"; badge_txt = "URGENT"; bg = "#2A0A0A"
        elif delta_j < 365:
            badge_col = "#D4A017"; badge_txt = f"{delta_j}j"; bg = "#1A1008"
        else:
            ans = delta_j / 365.25
            badge_col = "#C4922A"; badge_txt = f"{ans:.1f}ans"; bg = "#140810"
        auto_tag = " | AUTO" if is_auto else ""
        montant_tag = ""
        if montant > 0:
            if sens == "entree":
                montant_tag = f'<span style="color:#4DFF99;margin-left:10px;">+{montant:,.0f} EUR</span>'
            elif sens == "sortie":
                montant_tag = f'<span style="color:#FF7777;margin-left:10px;">-{montant:,.0f} EUR</span>'
            elif sens == "transfert":
                montant_tag = f'<span style="color:#FFD060;margin-left:10px;">{montant:,.0f} EUR</span>'
            elif sens == "perte":
                montant_tag = f'<span style="color:#FF7777;margin-left:10px;">{montant:,.0f} EUR/mois</span>'
        st.markdown(f'<div style="display:flex;align-items:flex-start;gap:12px;padding:10px 14px;background:{bg};border-radius:8px;margin:4px 0;border-left:3px solid {badge_col};"><div style="background:{badge_col};color:white;border-radius:6px;padding:3px 8px;font-size:11px;font-weight:700;white-space:nowrap;flex-shrink:0;">{badge_txt}</div><div><div style="color:#F0E6D8;font-size:13px;font-weight:600;">{action}{montant_tag}<span style="color:#C4922A;font-size:11px;margin-left:8px;">{cat}{auto_tag}</span></div><div style="color:#D0C0A8;font-size:12px;">{dt_s} | {age_j:.1f} ans | {note}</div></div></div>', unsafe_allow_html=True)
    return
