# ─── PAGE CAF/PCH ─────────────────────────────────────────────────────────────
def page_caf_pch(profil, cap):
    from datetime import date
    today = date.today()
    annee = str(today.year)

    st.subheader("AAH / CAF / PCH (Allocations)")

    # Lire AAH suivi
    db = db_wrapper.connect()
    # row_factory removed
    c = db.cursor()
    c.execute("SELECT * FROM aah_suivi ORDER BY mois ASC")
    rows = [dict(r) for r in c.fetchall()]
    db.close()

    # AAH annee en cours
    aah_courante = None
    for r in rows:
        if r['mois'] == annee:
            aah_courante = r
            break

    st.subheader("AAH - Suivi annuel")

    if aah_courante:
        prevu = aah_courante['montant_prevu']
        reel = aah_courante['montant_reel']
        affiche = reel if reel > 0 else prevu

        c1, c2, c3 = st.columns(3)
        with c1:
            st.metric("AAH prevue " + annee, f"{prevu:,.0f} EUR/mois")
        with c2:
            st.metric("AAH reelle " + annee, f"{reel:,.0f} EUR/mois" if reel > 0 else "Pas encore saisie")
        with c3:
            st.metric("AAH utilisee dans les calculs", f"{affiche:,.0f} EUR/mois")

        st.divider()
        st.write("**Saisir le montant AAH reel pour cette annee :**")
        nouveau = st.number_input("Montant AAH mensuel reel (EUR)", value=float(reel if reel > 0 else prevu), key="aah_saisie")
        if st.button("Enregistrer AAH " + annee):
            db2 = db_wrapper.connect()
            db2.execute("UPDATE aah_suivi SET montant_reel=%s, date_saisie=%s WHERE mois=%s", (nouveau, str(today), annee))
            db2.commit()
            db2.close()
            st.success(f"AAH {annee} enregistree : {nouveau:,.0f} EUR/mois")
            st.rerun()
    else:
        st.info(f"Pas de prevision AAH pour {annee}")

    # Tableau complet
    st.divider()
    st.subheader("Historique AAH prevu vs reel")
    for r in rows:
        reel_txt = f"{r['montant_reel']:,.0f} EUR" if r['montant_reel'] > 0 else "—"
        prevu_txt = f"{r['montant_prevu']:,.0f} EUR"
        ecart = ""
        if r['montant_reel'] > 0 and r['montant_reel'] != r['montant_prevu']:
            diff = r['montant_reel'] - r['montant_prevu']
            ecart = f" (ecart: {diff:+,.0f} EUR)"
        st.write(f"**{r['mois']}** | Prevu: {prevu_txt} | Reel: {reel_txt}{ecart}")
        if r.get('note'):
            st.caption(r['note'])

    # PCH
    st.divider()
    st.subheader("PCH - Prestation Compensation Handicap")
    pch = profil.get('pch_mensuel', 0)
    st.metric("PCH mensuelle", f"{pch:,.0f} EUR/mois")
    st.caption("La PCH est versee par le departement pour compenser les consequences du handicap.")

    # Resume
    st.divider()
    st.subheader("Resume mensuel")
    aah_m = 0
    if aah_courante:
        aah_m = aah_courante['montant_reel'] if aah_courante['montant_reel'] > 0 else aah_courante['montant_prevu']
    loyer = profil.get('loyer_net', 0)
    parents = 325
    c1, c2, c3, c4 = st.columns(4)
    with c1:
        st.metric("AAH", f"+{aah_m:,.0f} EUR")
    with c2:
        st.metric("Loyers LMNP", f"+{loyer:,.0f} EUR")
    with c3:
        st.metric("Versement parents", f"-{parents:,.0f} EUR")
    with c4:
        reste = aah_m + loyer - parents
        st.metric("Reste pour vivre", f"{reste:,.0f} EUR")


def page_inflation(profil, cap):
    titre("📈 MODULE INFLATION — POUVOIR D'ACHAT RÉEL")

    C = capital_total(cap)
    r = profil['rendement_annuel']
    rail = profil['rail_mensuel']
    aah = profil['aah_mensuel']
    loyer = profil['loyer_net']

    inf = st.slider("Taux d'inflation annuel (%)", 0.0, 4.0, 1.5, 0.1) / 100
    st.markdown(f'<div style="background:linear-gradient(145deg, #1A0D12 0%, #150A10 100%);border-radius:8px;padding:12px 16px;margin:8px 0;color:#DDCCBB;font-size:13px;">Avec une inflation de <b>{inf*100:.1f}%/an</b>, 2 760€/mois aujourd&#39;hui vaudront <b>{rail*(1+inf)**10:,.0f}€/mois dans 10 ans</b> et <b>{rail*(1+inf)**20:,.0f}€/mois dans 20 ans</b> en pouvoir d&#39;achat réel.</div>', unsafe_allow_html=True)

    r_m = (1+r)**(1/12)-1
    def A(n): return ((1+r)**n-1)/r_m if r_m>0 else n
    def P(n): return (1+r)**n
    pp1 = rail - aah - loyer
    pp2 = rail - loyer
    immo = 219000*(1.015**14)
    C64 = C*P(14)-pp1*A(14)+immo
    C80 = C64*P(16)-pp2*A(16)
    C92_nom = C80*P(12)-pp2*A(12)

    # En valeur réelle (déflatée)
    pts_nom = {}; pts_reel = {}
    for age in [50,56,60,64,70,75,80,85,90,92]:
        n = age-50
        if age<=64: v=C*P(n)-pp1*A(n)
        elif age<=80: v=C64*P(age-64)-pp2*A(age-64)
        else: v=C80*P(age-80)-pp2*A(age-80)
        pts_nom[age]=round(v,0)
        pts_reel[age]=round(v/(1+inf)**n, 0)

    c1,c2 = st.columns(2)
    with c1:
        kpi("C92 nominal", f"{C92_nom:,.0f} €", "Valeur face aux billets", "bleu")
    with c2:
        c92_reel = pts_reel[92]
        coul = "vert" if c92_reel >= 50000 else "orange"
        kpi("C92 en pouvoir d'achat réel", f"{c92_reel:,.0f} €", f"Ce que valent ces euros en 2026 · inflation {inf*100:.1f}%/an", coul)

    titre("Trajectoire nominale vs réelle")
    try:
        import plotly.graph_objects as go
        ages = list(pts_nom.keys())
        fig = go.Figure()
        fig.add_trace(go.Scatter(x=ages, y=list(pts_nom.values()), name="Nominal",
            line=dict(color='#C4922A',width=2), mode='lines+markers'))
        fig.add_trace(go.Scatter(x=ages, y=list(pts_reel.values()), name="Pouvoir d'achat réel",
            line=dict(color='#D4A017',width=2,dash='dash'), mode='lines+markers'))
        fig.add_hline(y=50000, line_dash="dot", line_color="#1A6B4B", annotation_text="Cible 50k€")
        fig.update_layout(plot_bgcolor='#140810',paper_bgcolor='#140810',font_color='#CCC',
            height=300,margin=dict(t=20,b=0,l=0,r=0),
            xaxis=dict(gridcolor='#2A0A12'),yaxis=dict(gridcolor='#2A0A12'),
            legend=dict(bgcolor='#140810'))
        st.plotly_chart(fig, width='stretch')
    except: pass

    titre("💡 Option : Rail indexé sur inflation")
    st.markdown("Et si on augmentait la pioche de 1,5%/an pour maintenir le pouvoir d&#39;achat ?")

    # Rail croissant
    r_m2 = (1+r)**(1/12)-1
    rail_croissant_c92 = None
    c_sim = C; rail_sim = rail
    for annee in range(42):
        croissance = rail_sim * (1+inf) / 12
        c_sim = c_sim * (1+r)**(1/12) - croissance
    c_sim_final = c_sim
    coul_croiss = "vert" if c_sim_final >= 50000 else "rouge"
    kpi(f"C92 avec rail +{inf*100:.1f}%/an", f"{c_sim_final:,.0f} €",
        f"Rail à 92 ans : {rail*(1+inf)**42:,.0f}€/mois · Faisable si capital suffisant", coul_croiss)



